void GateHandler::OnPacket(Corsairs::Net::RPacket& packet)
{
    GateServer* gt = &_app->m_gtarray[_gateIndex];
    if (!gt->IsValid()) return;
    _app->ProcessData(gt, packet);
}

void GateHandler::OnDisconnected(int reason)
{
    //  recv thread    ,   game thread
    _app->m_pendingDisconnect.store(_gateIndex);
}

