void GameServerApp::DisconnectGate(GateServer* pGate)
{
    if (pGate == nullptr) return;

    //   GateServer
    for (int i = 0; i < m_gtnum; ++i)
    {
        if (&m_gtarray[i] == pGate)
        {
            m_gateClients[i].Disconnect();
            pGate->Invalid();
            return;
        }
    }
}

// 
//  ProcessData    ( PKQueue  ProcessData)
// 

void GameServerApp::ProcessData(GateServer* gt, Corsairs::Net::RPacket& pk)
{
    if (gt == nullptr) return;

    uint16_t cmd = pk.GetCmd();

    // OnServeCall-: SESS-echo (  C++  .NET GateServer)
    if (cmd == CMD_TM_KICKCHA || cmd == CMD_TM_OFFLINE_MODE)
    {
        HandleServeCall(gt, pk);
        return;
    }

    int msg_id;
    switch (cmd)
    {
        case CMD_MM_GATE_CONNECT:
		    ToLogService("network", "ProcessData Gate_Connect");
            msg_id = NETMSG_GATE_CONNECTED;
            break;

        case CMD_MM_GATE_RELEASE:
            msg_id = NETMSG_GATE_DISCONNECT;
            break;

        default:
            msg_id = NETMSG_PACKET;
            break;
    }

    g_pGameApp->ProcessNetMsg(msg_id, gt, pk);
}

//
//  HandleServeCall   sync-  SESS-echo
// 

void GameServerApp::HandleServeCall(GateServer* gt, Corsairs::Net::RPacket& pk)
{
    uint32_t sess = pk.GetSess();
    uint16_t cmd = pk.GetCmd();

    Corsairs::Net::WPacket retpk(256);
    retpk.WriteSess(sess);

    switch (cmd)
    {
    case CMD_TM_KICKCHA:
    {
        auto const m = std::lock_guard{m_mutdisconn};
        Corsairs::Net::Msg::TmKickChaMessage kickMsg;
        Corsairs::Net::Msg::deserialize(pk, kickMsg);
        long lChaDbID = static_cast<long>(kickMsg.charDbId);
        CPlayer* pCOldPly = g_pGameApp->FindPlayerByDBChaID(lChaDbID);
        if (!pCOldPly || !pCOldPly->IsValid())
        {
            retpk.WriteInt64(0);
        }
        else
        {
            pCOldPly->GetCtrlCha()->BreakAction();
            pCOldPly->MisLogout();
            pCOldPly->MisGooutMap();
            g_pGameApp->ReleaseGamePlayer(pCOldPly);
            retpk.WriteInt64(1);
        }
        break;
    }
    case CMD_TM_OFFLINE_MODE:
    {
        Corsairs::Net::Msg::TmOfflineModeMessage offlineMsg;
        Corsairs::Net::Msg::deserialize(pk, offlineMsg);
        auto player = Corsairs::Util::ToPointer<CPlayer>(offlineMsg.playerPtr);
        CCharacter* pCCha{};

        const auto return_code = [&]
        {
            if (!player)
                return ReturnCode::OfflineMode::Unknown;

            if (player->GetGateAddr() != static_cast<DWORD>(offlineMsg.gateAddr))
                return ReturnCode::OfflineMode::Unknown;

            if (!player->IsValid())
                return ReturnCode::OfflineMode::Unknown;

            if (player->GetMainCha()->GetPlayer() != player)
                return ReturnCode::OfflineMode::Unknown;

            if (!g_Config.m_bOfflineMode)
                return ReturnCode::OfflineMode::Disabled;

            if (pCCha = player->GetCtrlCha(); !pCCha)
                return ReturnCode::OfflineMode::Unknown;

            if (!pCCha->IsLiveing())
                return ReturnCode::OfflineMode::Dead;

            if (auto map = pCCha->GetSubMap();
                map && !map->CanSavePos())
                return ReturnCode::OfflineMode::Refuse;

            if (pCCha->IsBoat())
                return ReturnCode::OfflineMode::Refuse;

            return ReturnCode::OfflineMode::Success;
        }();

        if (return_code != ReturnCode::OfflineMode::Success)
        {
            retpk.WriteInt64(static_cast<uint8_t>(return_code));
            break;
        }

        constexpr auto hour_in_ms = 60 * 60 * 1000;
        pCCha->_dwStallTick = GetTickCount() + (g_Config.m_dwStallTime * hour_in_ms);
        g_pGameApp->CanReceiveRequests(player->GetID(), false);
        player->SetCanReceiveRequests(false);
        retpk.WriteInt64(static_cast<uint8_t>(return_code));
        break;
    }
    default:
        return; //      
    }

    gt->SendData(retpk);
}

