bool GameServerApp::AddPlayer(GatePlayer* gtplayer, GateServer* gt, unsigned long gtaddr)
{
    if (gt == nullptr || gtplayer == nullptr) return false;
    if (!gt->IsValid()) return false;

    gtplayer->SetGate(gt);
    gtplayer->SetGateAddr(gtaddr);

    auto* p = static_cast<CPlayer*>(gtplayer);
    auto [it, inserted] = gt->m_playerlist.insert(p);
    if (!inserted) {
        ToLogService("common", "when insert character, dbid {}, find it already in the list!", gtplayer->GetDBChaId());
        return false;
    }
    return true;
}

bool GameServerApp::DelPlayer(GatePlayer* gtplayer)
{
    if (gtplayer == nullptr) return false;

    GateServer* gt = gtplayer->GetGate();
    if (gt == nullptr || !gt->IsValid()) return false;

    gt->m_playerlist.erase(static_cast<CPlayer*>(gtplayer));
    return true;
}

