void GameServerApp::BeginGetGate(void) {
	m_listcurgt = 0;
}

GateServer* GameServerApp::GetNextGate(void) {
	while (m_listcurgt < m_gtnum) {
		if (m_gtarray[m_listcurgt++].IsValid())
			return m_gtarray + (m_listcurgt - 1);
	}
	return nullptr;
}
